# Utility module with helper functions and classes

class Wrapper:
    text: str

    def __init__(self, text: str):
        self.text = text

    def wrap_with(self, prefix: str, suffix: str) -> str:
        return prefix + self.text + suffix


def max_value(a: float, b: float) -> float:
    if a > b:
        return a
    return b


def clamp(value: int, min_val: int, max_val: int) -> int:
    if value < min_val:
        return min_val
    if value > max_val:
        return max_val
    return value


def format_number(value: float, decimals: int) -> str:
    multiplier: float = pow(10.0, float(decimals))
    rounded: float = round(value * multiplier) / multiplier
    result: str = str(rounded)
    dot_found: bool = False
    for c in result:
        if c == ".":
            dot_found = True
            break
    if not dot_found:
        result = result + ".0"
    return result


class Pair:
    first: int
    second: int

    def __init__(self, first: int, second: int):
        self.first = first
        self.second = second

    def swap(self):
        temp: int = self.first
        self.first = self.second
        self.second = temp
